import{c as t,Q as a,j as i,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Andrej Karpathy Skills - LLM Coding Guidelines That Prevent Common Mistakes","description":"","frontmatter":{"url":"https://pyshine.com/Andrej-Karpathy-Skills-LLM-Coding-Guidelines/","title":"Andrej Karpathy Skills - LLM Coding Guidelines That Prevent Common Mistakes","author":"PyShine","date":"2026-04-09T00:00:00.000Z","status":"SUCCESS"},"headers":[],"relativePath":"research/ai-articles/07-pyshine-karpathy-skills-guidelines.md","filePath":"research/ai-articles/07-pyshine-karpathy-skills-guidelines.md","lastUpdated":1779894392000}'),s={name:"research/ai-articles/07-pyshine-karpathy-skills-guidelines.md"};function l(n,e,r,p,d,h){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="andrej-karpathy-skills-llm-coding-guidelines-that-prevent-common-mistakes" tabindex="-1">Andrej Karpathy Skills: LLM Coding Guidelines That Prevent Common Mistakes <a class="header-anchor" href="#andrej-karpathy-skills-llm-coding-guidelines-that-prevent-common-mistakes" aria-label="Permalink to &quot;Andrej Karpathy Skills: LLM Coding Guidelines That Prevent Common Mistakes&quot;">​</a></h1><h2 id="核心摘要" tabindex="-1">核心摘要 <a class="header-anchor" href="#核心摘要" aria-label="Permalink to &quot;核心摘要&quot;">​</a></h2><p>本文介紹了 <code>andrej-karpathy-skills</code> 倉庫中的四項核心原則，這些原則設計用來解決 LLM 輔助編碼中的常見陷阱。文章強調了這些指南如何通過改變 AI 代理的決策過程，從根本上改善代碼品質。</p><p><strong>識別的三大問題</strong></p><ol><li><strong>無聲假設（Silent Assumptions）</strong>：LLM 做出假設而無需尋求澄清，直接執行導致錯誤實現</li><li><strong>複雜過度（Unnecessary Complexity）</strong>：LLM 傾向於用投機性功能和過度抽象化來膨脹代碼</li><li><strong>副效應編輯（Collateral Changes）</strong>：修改代碼時無意中引入對無關部分的改動</li></ol><p><strong>四項核心原則詳解</strong></p><p><strong>原則一：編碼前思考（Think Before Coding）</strong></p><p>在實施前，要求模型明確陳述其對需求的理解和假設。當遇到模糊指令時，應提出多個可能的解釋，由人類開發者選擇正確方向。這一原則改變了 AI 從被動執行者到主動問題求解者的角色。</p><p><strong>原則二：簡潔優先（Simplicity First）</strong></p><p>實現僅請求的功能，不添加投機性特性，不創建單用途的抽象層，不設計超出必要的靈活性。這個原則迫使 AI 考慮代碼的簡潔性，同時保持功能完整性。</p><p><strong>原則三：精準修改（Surgical Changes）</strong></p><p>進行最小化的、針對性的編輯。修改的每一行代碼都應直接歸因於用戶的請求。避免同時進行「代碼改進」、「風格統一」或「重構」——這些往往引入微妙的 bug。</p><p><strong>原則四：目標驅動執行（Goal-Driven Execution）</strong></p><p>將模糊的指令轉化為具體的、可測試的成功標準。與其說「修復這個問題」，不如說「寫一個復現問題的單元測試，然後讓測試通過」。這使 LLM 能夠獨立迭代直至達成明確的目標。</p><p><strong>安裝與使用</strong></p><p>該指南提供兩種使用方式：</p><ol><li><strong>Claude Code 外掛</strong>：將 Karpathy Skills 作為全局外掛安裝，一次性設置所有項目</li><li><strong>項目級 CLAUDE.md</strong>：在每個項目根目錄放置 CLAUDE.md 檔案，允許按項目自定義</li></ol><p><strong>設計哲學</strong></p><p>這些指南的設計遵循「謹慎優於速度」的原則，特別適用於非平凡的開發任務。簡單的解決方案不僅減少維護負擔，也大大降低了潛在 bug 的風險。</p><p><strong>應用場景</strong></p><ul><li>複雜代碼重構</li><li>遺留系統現代化</li><li>關鍵路徑功能開發</li><li>跨模塊集成工作</li></ul><h2 id="關鍵引述" tabindex="-1">關鍵引述 <a class="header-anchor" href="#關鍵引述" aria-label="Permalink to &quot;關鍵引述&quot;">​</a></h2><blockquote><p>&quot;The models make wrong assumptions on your behalf and just run along with them without checking.&quot; — Andrej Karpathy（識別 AI 編碼的根本問題）</p></blockquote><blockquote><p>&quot;They really like to overcomplicate code and APIs, bloat abstractions...&quot; — Andrej Karpathy（LLM 過度工程化的傾向）</p></blockquote><blockquote><p>&quot;Principles can be installed as Claude Code plugin or added as project CLAUDE.md file&quot; — 靈活的實施選項</p></blockquote><h2 id="實踐建議" tabindex="-1">實踐建議 <a class="header-anchor" href="#實踐建議" aria-label="Permalink to &quot;實踐建議&quot;">​</a></h2><ul><li><strong>循序漸進</strong>：先從核心的四項原則開始，根據實際情況逐步調整</li><li><strong>團隊同步</strong>：在團隊中分享 CLAUDE.md，確保對 AI 代理行為的共同理解</li><li><strong>度量成效</strong>：追蹤代碼審查時間、修訂次數等指標，量化改善效果</li><li><strong>持續改進</strong>：根據項目特點定製原則，但保持核心思想不變</li></ul>',27)])])}const c=t(s,[["render",l]]);export{u as __pageData,c as default};
